'use client';

import { useState, useRef, useEffect, useCallback } from 'react';
import ModelPickerModal from '../components/ModelPickerModal';

const USER_ID = 'web';

interface AgentInfo {
  id: string;
  name: string;
  emoji: string;
  model: string;
}

interface ChatMessage {
  id?: number;
  ts: number;
  user_id: string;
  role: 'user' | 'agent';
  content: string;
  model?: string;
  openclaw_session_id?: string;
  mediaType?: string;
  mediaName?: string;
}

interface AgentConversation {
  agentId: string;
  messages: ChatMessage[];
  sessionId: string;
}

interface ChatSessionInfo {
  sessionId: string;
  agentId: string;
  label: string;
  msgCount: number;
  preview: string;
  lastTs: number;
  source: 'web' | 'telegram';
}

// Emoji name → actual emoji mapping for OpenClaw identity.emoji
const EMOJI_MAP: Record<string, string> = {
  eye: '👁️',
  robot: '🤖',
  fire: '🔥',
  globe_with_meridians: '🌐',
  rocket: '🚀',
  brain: '🧠',
  star: '⭐',
