import { NextResponse, type NextRequest } from 'next/server';
import WebSocket from 'ws';

export const dynamic = 'force-dynamic';
export const maxDuration = 90;

const WS_URL = 'ws://127.0.0.1:18789';

const AGENT_KEY_PREFIX: Record<string, string> = {
  ops: 'agent:ops',
  main: 'agent:main',
};

function getDefaultSessionKey(agentId: string, userId: string): string {
  const prefix = AGENT_KEY_PREFIX[agentId] || `agent:${agentId}`;
  return `${prefix}:chat:${userId}`;
}

function rpcCall(method: string, params: any): Promise<any> {
  return new Promise((resolve, reject) => {
    const ws = new WebSocket(WS_URL);
    const id = crypto.randomUUID();
    const timeout = setTimeout(() => {
      ws.close();
      reject(new Error(`RPC timeout: ${method}`));
    }, 25000);

    ws.on('open', () => {
      ws.send(JSON.stringify({ jsonrpc: '2.0', id, method, params }));
    });

    ws.on('message', (data) => {
      let msg: any;
      try {
        msg = JSON.parse(data.toString());
      } catch {
        return;
      }
      if (msg.id === id) {
        clearTimeout(timeout);
        ws.close();
        if (msg.error) reject(new Error(msg.error.message || JSON.stringify(msg.error)));
        else resolve(msg.result);
      }
    });

    ws.on('error', (err) => {
      clearTimeout(timeout);
      reject(err);
    });
  });
}

export async function POST(request: NextRequest): Promise<Response> {
  let body: any;
  try {
    body = await request.json();
  } catch {
    return NextResponse.json({ error: 'Invalid JSON' }, { status: 400 });
  }

  const { message, agentId = 'ops', sessionKey, model } = body;
  if (!message?.trim()) {
    return NextResponse.json({ error: 'message required' }, { status: 400 });
  }

  const safeMsg = message.trim();

  // Determine session key: use provided one, or derive a default
  const effectiveSessionKey = sessionKey && sessionKey !== 'new'
    ? sessionKey
    : getDefaultSessionKey(agentId, 'web');

  // Build chat.send params
  const sendParams: any = {
    sessionKey: effectiveSessionKey,
    message: safeMsg,
    deliver: false,
  };
  if (model && model.trim()) {
    sendParams.model = model.trim();
  }

  // Stream SSE — connect WebSocket and relay events
  const encoder = new TextEncoder();
  const stream = new ReadableStream({
    async start(controller) {
      try {
        const ws = new WebSocket(WS_URL);
        const sendId = crypto.randomUUID();
        let streamDone = false;
        let streamError: string | null = null;
        let responseSessionKey: string | null = null;

        const closeStream = (doneMessage: string) => {
          if (streamDone) return;
          streamDone = true;
          if (responseSessionKey) {
            const meta = JSON.stringify({ sessionKey: responseSessionKey });
            controller.enqueue(encoder.encode(`data: ${meta}\n\n`));
          }
          controller.enqueue(encoder.encode(`data: ${doneMessage}\n\n`));
          controller.close();
          ws.close();
        };

        ws.on('open', () => {
          ws.send(JSON.stringify({
            jsonrpc: '2.0',
            id: sendId,
            method: 'chat.send',
            params: sendParams,
          }));
        });

        ws.on('message', (data) => {
          if (streamDone) return;
          let msg: any;
          try {
            msg = JSON.parse(data.toString());
          } catch {
            return;
          }

          // Response to our send request
          if (msg.id === sendId) {
            // This is the initial ack — session info
            if (msg.result?.sessionKey) {
              responseSessionKey = msg.result.sessionKey;
            }
            return;
          }

          // Streaming events
          if (msg.method === 'chat.event' && msg.params) {
            const { state, message: eventMsg, errorMessage } = msg.params;

            if (state === 'delta' && eventMsg?.content) {
              const text = extractText(eventMsg.content);
              if (text) {
                const payload = JSON.stringify({ choices: [{ delta: { content: text } }] });
                controller.enqueue(encoder.encode(`data: ${payload}\n\n`));
              }
            } else if (state === 'final' || state === 'done') {
              // Send any remaining content from the final message
              if (eventMsg?.content) {
                const text = extractText(eventMsg.content);
                if (text) {
                  const payload = JSON.stringify({ choices: [{ delta: { content: '\n' + text } }] });
                  controller.enqueue(encoder.encode(`data: ${payload}\n\n`));
                }
              }
              closeStream('[DONE]');
            } else if (state === 'aborted') {
              closeStream('[ABORTED]');
            } else if (state === 'error') {
              streamError = errorMessage || 'Agent error';
              closeStream('[ERROR]');
            }
          }
        });

        ws.on('error', (err) => {
          if (!streamDone) {
            streamError = err.message;
            closeStream('[ERROR]');
          }
        });

        // Safety timeout — close stream after 85s
        setTimeout(() => {
          if (!streamDone) {
            closeStream('[DONE]');
          }
        }, 85000);

      } catch (err: any) {
        const meta = JSON.stringify({ error: err.message || 'Connection failed' });
        controller.enqueue(encoder.encode(`data: ${meta}\n\n`));
        controller.enqueue(encoder.encode('data: [ERROR]\n\n'));
        controller.close();
      }
    },
  });

  return new Response(stream, {
    headers: {
      'Content-Type': 'text/event-stream',
      'Cache-Control': 'no-cache',
      'X-Accel-Buffering': 'no',
    },
  });
}

function extractText(content: any): string {
  if (!content) return '';
  if (typeof content === 'string') return content;
  if (Array.isArray(content)) {
    return content
      .map((c: any) => (typeof c === 'object' && c.type === 'text' ? c.text : ''))
      .filter(Boolean)
      .join('');
  }
  if (typeof content === 'object' && content.text) return content.text;
  return '';
}

