import { NextResponse, type NextRequest } from 'next/server';
import WebSocket from 'ws';

export const dynamic = 'force-dynamic';

const WS_URL = 'ws://127.0.0.1:18789';

function rpcCall(method: string, params: any): Promise<any> {
  return new Promise((resolve, reject) => {
    const ws = new WebSocket(WS_URL);
    const id = crypto.randomUUID();
    const timeout = setTimeout(() => {
      ws.close();
      reject(new Error(`RPC timeout: ${method}`));
    }, 15000);

    ws.on('open', () => {
      ws.send(JSON.stringify({ jsonrpc: '2.0', id, method, params }));
    });

    ws.on('message', (data) => {
      let msg: any;
      try {
        msg = JSON.parse(data.toString());
      } catch {
        return;
      }
      if (msg.id === id) {
        clearTimeout(timeout);
        ws.close();
        if (msg.error) reject(new Error(msg.error.message || JSON.stringify(msg.error)));
        else resolve(msg.result);
      }
    });

    ws.on('error', (err) => {
      clearTimeout(timeout);
      reject(err);
    });
  });
}

/**
 * Determine session source from its key pattern.
 */
function getSourceLabel(key: string): string {
  if (!key) return 'unknown';
  if (key.includes(':chat:') || key.includes(':web:')) return 'web';
  if (key.includes(':telegram:')) return 'telegram';
  if (key.includes(':subagent:') || key.startsWith('spawn-child')) return 'subagent';
  if (key.includes(':main')) return 'telegram';
  if (key.includes(':whatsapp:')) return 'whatsapp';
  if (key.includes(':discord:')) return 'discord';
  if (key.includes(':signal:')) return 'signal';
  return 'other';
}

export async function GET(request: NextRequest): Promise<NextResponse> {
  const agentId = request.nextUrl.searchParams.get('agentId') || '';
  const limit = Math.min(parseInt(request.nextUrl.searchParams.get('limit') || '100', 10) || 100, 500);

  try {
    const result = await rpcCall('sessions.list', { limit, showArchived: false });
    const sessions: any[] = result?.sessions || result || [];

    // Filter by agent if specified
    let filtered = sessions;
    if (agentId) {
      filtered = sessions.filter((s: any) => {
        const key: string = s.key || '';
        return key.startsWith(`agent:${agentId}:`) || key.startsWith(`agent:${agentId}:`);
      });
    }

    // Map to clean format for the UI
    const mapped = filtered.map((s: any) => ({
      sessionId: s.sessionId || '',
      key: s.key || '',
      label: s.label || s.displayName || s.key?.split(':').slice(-2).join(':') || 'Chat',
      msgCount: s.msgCount || s.messageCount || 0,
      preview: s.preview || '',
      lastTs: s.updatedAt || s.ts || 0,
      source: getSourceLabel(s.key || ''),
      model: s.model || '',
      kind: s.kind || 'direct',
    }));

    return NextResponse.json(mapped);
  } catch (e: any) {
    console.error('sessions.list RPC error:', e.message);
    return NextResponse.json({ error: e.message }, { status: 500 });
  }
}

