const newSession = useCallback(() => {
  if (abortRef.current) abortRef.current.abort();
  // 'new' è uno stato sentinella: al prossimo send l'API genererà un ID reale.
  setConversations(prev => ({
    ...prev,
    [selectedAgent]: { agentId: selectedAgent, messages: [], sessionId: 'new' },
  }));
  setSelectedSessionId(null);
  setSelectedModel(''); // reset model per nuova sessione
  setStreaming(false);
  setPastedFiles([]);
  inputRef.current?.focus();
}, [selectedAgent]);

const loadSession = useCallback(async (sessionId: string) => {
  if (abortRef.current) abortRef.current.abort();
  setStreaming(false);
  setSelectedSessionId(sessionId);
  const agentId = selectedAgent;
  try {
    const res = await fetch(`/api/chat/history?userId=${USER_ID}`);
    const data = await res.json();
    if (Array.isArray(data)) {
      const msgs = data.filter((m: ChatMessage) => m.openclaw_session_id === sessionId || !m.openclaw_session_id);
      setConversations(prev => ({
        ...prev,
        [agentId]: { agentId, messages: msgs, sessionId },
      }));
      // Carica model dall'ultimo messaggio agente con model valorizzato
      const lastAgentWithModel = [...msgs].reverse().find(
        (m: ChatMessage) => m.role === 'agent' && m.model && m.model !== ''
      );
      if (lastAgentWithModel?.model) {
        setSelectedModel(lastAgentWithModel.model);
      } else {
        setSelectedModel('');
      }
    }
  } catch {}
  setSidebarOpen(false);
}, [selectedAgent]);

